import { useState } from 'react';

function LikeButton() {
  const [likes, setLikes] = useState(0);

  return (
    <div>
      <p>{likes} {likes === 1 ? 'Like' : 'Likes'}</p>
      <button onClick={() => setLikes(prev => prev + 1)}>
        Like
      </button>
    </div>
  );
}

export default LikeButton;
